pub fn pretty_print(val: &Value) -> String {
    pretty_fmt(val, 0)
}

fn pretty_fmt(val: &Value, depth: usize) -> String {
    let indent = "  ".repeat(depth);
    let inner_indent = "  ".repeat(depth + 1);
    match val {
        Value::Null => "null".to_string(),
        Value::Bool(b) => b.to_string(),
        Value::Number(n) => n.to_string(),
        Value::Str(s) => format!("\"{}\"" , s),
        Value::Array(arr) => {
            if arr.is_empty() {
                return "[]".to_string();
            }
            let items: Vec<String> = arr.iter()
                .map(|v| format!("{}{}", inner_indent, pretty_fmt(v, depth + 1)))
                .collect();
            format!("[\n{}\n{}]", items.join(",\n"), indent)
        }
        Value::Object(obj) => {
            if obj.is_empty() {
                return "{}".to_string();
            }
            let pairs: Vec<String> = obj.iter()
                .map(|(k, v)| format!("{}\"{}\": {}", inner_indent, k, pretty_fmt(v, depth + 1)))
                .collect();
            format!("{{\n{}\n{}}}", pairs.join(",\n"), indent)
        }
    }
}
